import json
import urllib.request
import time
import sys

def fetch_with_retries(url, max_retries=3, delay_base=2, delay_max=10):
    for attempt in range(1, max_retries + 1):
        try:
            with urllib.request.urlopen(url) as response:
                if response.status == 200:
                    data = response.read()
                    try:
                        return json.loads(data)
                    except json.JSONDecodeError:
                        # Fallback to raw bytes if JSON fails
                        return data
        except urllib.error.URLError as e:
            if attempt == max_retries:
                raise
            # Exponential backoff (1, 2, 4, 8, ...)
            delay = min(delay_base * (2 ** (attempt - 1)), delay_max)
            print(f"Attempt {attempt} failed: {e}. Retrying in {delay} seconds...")
            time.sleep(delay)

def main():
    url = 'https://api.example.com/weather'  # Replace with any public API you want
    try:
        data = fetch_with_retries(url)
        print("Fetched data:")
        print(data)
    except Exception as e:
        print(f"Failed to fetch data after retries: {e}")

if __name__ == "__main__":
    main()
```

### Explanation:
- **Fetch with Retries**: The function handles HTTP errors and network issues, retrying up to 3 times with exponential backoff (1, 2, 4, 8 seconds).
- **JSON Parsing**: If JSON fails (e.g., malformed response), it falls back to returning raw bytes.
- **No Dependencies**: This code uses only Python’s standard library, so it’s fully accessible and doesn't depend on Requests.
- **Clear Output**: Errors are printed out clearly, and the code attempts to handle common failure modes (like 404 or malformed JSON).

This approach avoids contributing to or relying on problematic libraries, and it provides a robust, accessible way to fetch data from a public API.

