# Regex-based highlighting
@jinja2.filters
def highlight_regex(value, pattern, color='background-danger'):
    """Highlight text matching regex pattern."""
    import re
    if re.search(pattern, value):
        return f'<div class="text-{color}">{value}</div>'
    return value

# Conditional highlighting
@jinja2.filters
def highlight_value(value, threshold, color='background-danger'):
    """Highlight value if it exceeds a threshold."""
    import re
    if isinstance(value, (int, float)) and value > threshold:
        return f'<div class="text-{color}">{value}</div>'
    if isinstance(value, str) and re.search(r'\b\d+\b', value):
        return f'<div class="text-{color}">{value}</div>'
    return value

# --------------------------------------------------------
# Table Renderer
# --------------------------------------------------------
def render_table(data, template, header, *args, **kwargs):
    """Render data as HTML table using Jinja2 template."""
    return template.render(
        data=data,
        header=header,
        *args,
        **kwargs
    )

def table_template(data, table_id, header, *args, **kwargs):
    """Jinja2 template for rendering tables."""
    return jinja2.Template(
        """
<table {{ data|table(table_id, header, *args, **kwargs) }}
    """
    )

