<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>{{ title }}</title>
    <style>
        {{ css|safe }}
    </style>
</head>
<body>
    {% block header -%}
    {% endblock %}
    {{ content }}
    {% block footer -%}
    {% endblock %}
</body>
</html>
""")

