def render_report(data, template_path, report_title, css=None, *args, **kwargs):
    """Render a report from data and template."""
    if css is None:
        css = '''
            body { font-family: Arial, sans-serif; }
            table { border-collapse: collapse; }
            th, td { padding: 12px; text-align: left; border: 1px solid #ddd; }
            .text-danger { background: #f44336; color: white; }
        '''
    template = BASE_TEMPLATE
    template.globals.update({
        "render_table": render_table,
        "table_template": table_template,
        "highlight_regex": highlight_regex,
        "highlight_value": highlight_value,
        "css": css,
    })
    template.globals["datetime"] = lambda x: datetime.fromisoformat(x).strftime("%B %d, %Y") if isinstance(x, str) else x
    return template.render(
        title=report_title,
        content=template_path,
        *args,
        **kwargs
