import requests
import time
from typing import Dict, Optional

API_URL = "http://api.openweathermap.org/data/2.5/weather?q={}&appid={}&units=metric"

def fetch_weather(city: str, max_retries: int = 3, delay: int = 1) -> Optional[Dict]:
    """Fetch weather data with retry logic."""
    for attempt in range(max_retries + 1):
        try:
            response = requests.get(API_URL.format(city, "YOUR_API_KEY", units="metric"))
            response.raise_for_status()
            return response.json()
        except requests.exceptions.HTTPError as http_err:
            if attempt == max_retries:
                raise http_err
            time.sleep(delay)
            delay *= 2
        except Exception as err:
            if attempt == max_retries:
                raise err
            time.sleep(delay)
            delay *= 2
    return None

def main():
    city = input("Enter city name: ").strip()
    try:
        weather = fetch_weather(city)
        if weather:
            print(f"Weather in {city}:")
            print(f"  Temperature: {weather['main']['temp']}°C")
