import requests
import time

class Retryer:
    def __init__(self, session, retries=3, backoff_factor=0.3, status_forcelist=(500, 502, 503, 504)):
        self.session = session
        self.retries = retries
        self.backoff_factor = backoff_factor
        self.status_forcelist = status_forcelist
        self.last_response = None
    def request(self, url, **kwargs):
        retries = self.retries
        while True:
            try:
                response = self.session.get(url, **kwargs)
                response.raise_for_status()
                self.last_response = response
                return response.json()
            except requests.exceptions.HTTPError as e:
                if response.status_code in self.status_forcelist and retries > 0:
                    retries -= 1
                    time.sleep(self.backoff_factor * (2 ** retries))
                else:
                    raise
            except requests.exceptions.RequestException as e:
                if retries > 0:
                    retries -= 1
                    time.sleep(self.backoff_factor * (2 ** retries))
                else:
                    raise Exception(f"Failed after {self.retries} retries: {url}") from e
            except Exception:
                if retries > 0:
                    retries -= 1
                    time.sleep(self.backoff_factor * (2 ** retries))
                else:
                    raise Exception(f"Failed after {self.retries} retries: {url}") from e

def fetch_data(url, retries=3, backoff_factor=0.3, status_forcelist=(500, 502, 503, 504)):
    session = requests.Session()
    retryer = Retryer(session, retries, backoff_factor, status_forcelist)
    try:
        return retryer.request(url)
    except Exception as e:
        return {"error": str(e)}

# Example usage
if __name__ == "__main__":
    url = "http://jsonplaceholder.typicode.com/posts"
    data = fetch_data(url)
    print(data)
